import { expect, it } from 'vitest'

import { omitEmpty } from './omit-empty'

it('Omit Empty Basic', ctx => {
  const date = new Date()
  const object = {
    // Should not be omitted
    a: { one: 1 },
    b: [1],
    c: 1,
    d: 0,
    e: 'string',
    k: date,
    l: false,

    // Should be omitted
    f: {},
    g: [],
    h: '',
    i: null,
    j: undefined,
  }

  const expected = {
    a: { one: 1 },
    b: [1],
    c: 1,
    d: 0,
    e: 'string',
    k: date,
    l: false,
  }

  const result = omitEmpty(object)
  expect(result).toEqual(expected)
})

it('Omit Empty Nested', ctx => {
  const object = {
    a: {
      one: {},
      two: [],
      three: 1,
      four: 'string',
    },
  }

  const expected = {
    a: {
      three: 1,
      four: 'string',
    },
  }

  const result = omitEmpty(object)
  expect(result).toEqual(expected)
})

it('Omit Empty Recursive', ctx => {
  const object = {
    a: {
      one: {},
      two: [],
      three: {
        alpha: {},
        beta: [],
        tetha: 1,
        gamma: 'string',
      },
    },
  }

  const expected = {
    a: {
      three: {
        tetha: 1,
        gamma: 'string',
      },
    },
  }

  const result = omitEmpty(object)
  expect(result).toEqual(expected)
})
